class NormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images with circular mask."""

    def __init__(self, patch_size=None, eps=1e-3, image_size=256, radius=119, device=torch.device('cpu'), step=1):
        super().__init__()
        self.patch_size = patch_size
        self.eps = eps
        self.image_size = image_size
        self.radius = radius
        self.register_buffer('mask', self.create_mask(image_size, radius, patch_size, step).to(device))
        self.ori_mask = self.mask
        self.step = step

    @staticmethod
    def create_mask(image_size, radius, patch_size=None, step=1):
        center = (image_size - 1) / 2  # Center at 127.5 for 256x256
        y = torch.arange(image_size, dtype=torch.float32)
        x = torch.arange(image_size, dtype=torch.float32)
        yy, xx = torch.meshgrid(y, x, indexing='ij')
        dist_sq = (xx - center) ** 2 + (yy - center) ** 2
        mask = (dist_sq <= radius ** 2).float().unsqueeze(0).unsqueeze(0)
        if patch_size is not None:
            mask = to_patches(mask, patch_size, step)
        return mask # Shape: (1, 1, H, W)

    def forward(self, x1, x2, weight_map=None):
        if self.patch_size is not None:
            x1 = to_patches(x1, self.patch_size, self.step)
            x2 = to_patches(x2, self.patch_size, self.step)

        assert x1.shape == x2.shape, "Input images must be the same size"

        x1 = x1[:, self.valid_idx, :, :]
        x2 = x2[:, self.valid_idx, :, :]
        x1 = x1 * self.mask
        x2 = x2 * self.mask

        _, c, h, w = x1.shape
        x1, x2 = self.norm(x1), self.norm(x2)

        if weight_map is None:
            # score = torch.einsum("b...,b...->b", x1, x2)
            score = (x1[self.mask == 1] * x2[self.mask == 1]).sum()
        else:
            if self.patch_size is not None:
                weight_map = to_patches(weight_map, self.patch_size, self.step)
            weight_map = weight_map[:, self.valid_idx, :, :]
            # score = torch.einsum("b...,b...,b...->b", x1, x2, weight_map)
            score = (x1[self.mask == 1] * x2[self.mask == 1] * weight_map[self.mask == 1]).sum()
        effective_pixels = self.mask_sum  # Total valid pixels per batch
        score /= effective_pixels + self.eps

        return score

    def norm(self, x):
        mask = self.mask.expand_as(x)
        # b, n, h, w = x.shape
        # with torch.no_grad():
        #     medians = torch.zeros(b, n, device=x.device)
        #
        #     for i in range(b):
        #         for j in range(n):
        #             img = x[i, j]  # [h, w]
        #             img_mask = mask[i, j]  # [h, w]
        #
        #             if img_mask.any():
        #                 masked_pixels = img[img_mask == 1]
        #                 medians[i, j] = torch.median(masked_pixels)
        #             else:
        #                 medians[i, j] = 0.0
        #     medians = medians.unsqueeze(-1).unsqueeze(-1)
        # x_centered = (x - medians) * mask

        mu = (x * mask).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        x_centered = (x - mu) * mask
        var = (x_centered ** 2).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        std = var.sqrt()
        return x_centered / (std + self.eps)

    def set_mask(self, tube_mask):

        if self.patch_size is not None:
            tube_mask = to_patches(tube_mask, self.patch_size, self.step)
        self.mask = tube_mask * self.ori_mask
        # plt.figure()
        # plt.imshow(self.mask.cpu().squeeze(0).permute(1, 2, 0), cmap='gray')
        # plt.show()

        valid = self.mask.sum(dim=[-2, -1], keepdim=True) <= 30
        idx = torch.where(~valid)
        valid_idx = idx[1]
        self.valid_idx = valid_idx
        self.mask = self.mask[:, valid_idx, :, :]
        self.mask_sum = self.mask.sum()


class MultiscaleNormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images at multiple scales."""
    def __init__(self, patch_sizes=[None], patch_weights=[1.0], eps=1e-5, device=torch.device('cpu'), step=[1]):
        super().__init__()

        assert len(patch_sizes) == len(patch_weights), "Each scale must have a weight"
        self.nccs = [
            NormalizedCrossCorrelation2d(patch_size, device=device, step=s) for patch_size, s in zip(patch_sizes, step)
        ]
        self.patch_weights = patch_weights
        self.step = step

    def forward(self, x1, x2, weight_map=None):
        scores = []
        for weight, ncc in zip(self.patch_weights, self.nccs):
            scores.append(weight * ncc(x1, x2, weight_map))
        return torch.stack(scores, dim=0).sum(dim=0)

    def set_mask(self, tube_mask):
        for ncc in self.nccs:
            ncc.set_mask(tube_mask)

