from einops import rearrange


def to_patches(x, patch_size, step=1):
    # x = x.unfold(2, patch_size, step=1).unfold(3, patch_size, step=1).contiguous()
    x = x.unfold(2, patch_size, step=step).unfold(3, patch_size, step=step).contiguous()
    # x = x.unfold(2, patch_size, step=patch_size // 2).unfold(3, patch_size, step=patch_size // 2).contiguous()
    return rearrange(x, "b c p1 p2 h w -> b (c p1 p2) h w")

